  "verses": [
    {
      "n": 21,
      "column": "left",
      "text": "Tas STIPRAJS mums par labbu eſt darri\nDEEWS irr preekſch mumſ/\ntas STIPRAJS DEEWS\nirr/ kas pilntgi iſpesti/ un pee ta\nKUNGA KUNGA irr tahs Jeſ-\nwefchanas no Nahwes.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Teesfham/ Deews ſadan-\nfibs fawn Eenaidneeko Galwu /\nun to Matto pillu Galwas Wir-\nfu to/ kas eeſch faueein Nofee-\ngumeen ſtaiga.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Tas KUNGS faſka : Ge\natweḍdifchu / es atweḍdifchu at-\nfak no Babsana/ es atweḍdifchu\natkak no Juhras Dſiltumeem.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Tadeht tawa Rahja tawu\nEenaidneeku Aſinis eemihdihs/\nun tawi Sunni laiſhs to paſchu.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Tawi Gahjumi ak Deews!\ntohp redseti/ manna STIP-\nRA DEEWA Gahjumi man-\nna Kehnika twehta Weeta.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Tee Dseedatajt eet pa-\npreekſchu / tee Spehletaji pak-\nkak/ tahs Meitas ar Bungahm\npaſcha Widdii.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Teizeet Deewu eeſch\ntahm Drandſehm to KUNGU/\nno Ifraëka *Awota.\n* Tas irr Kristus, kas no teem Tehwoem\nirr pehz tahs Meetas. Reem: 1, 3, 4. un: 9, 5.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Tur walda pahr teem tas\nmasajs Benjainins/tee Leel-Kun-\ngi no Juha ar fawahm Dran-\ndsibahm/ tee Leel-Kungi no Se-\nbulana/ tee Leel-Kungi no Naw-\ntata.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Taws Deews irr paweh-\nlejs tawat ( Walſtibai ) ſtiprai\nbuht/ ſtriprini ak Deews! ko tu\n"
    },
    {
      "n": 30,
      "column": "right",
      "text": "Behz-tawa Deewa Na-\nma eeſch Jerufalemes/ atneſſ-\ntee Kehnixti tew Dahwanas.\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Lamita to Swehru eek\nNeedras/to Wehrſchu Puſku/\nto Tautu Telteem/kas famih-\nNaudas pehz/ wiꞥſch iſka-\ntohs Laudis / kas labpra-\nkaro.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Tee Leeli-Kungi nahks\nEgiptes- Semmes/ ta Moh-\nSemme ſteigfees JawasRoh-\nus Deewu isſteept.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Juhs Semmes Walt-\nbas dseedajeet Deewam/ dſced-\njeet tam KUNGAM/ Sela.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Tam / kas eeſch wiſ-\nDebbetchu Debbeſim brauz/ k-\nno Eefahkuma irr/ raugi/ wiſ-\ndohs Jawam Pehrkonam ſpehz-\ngu Skanun.\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Dohdeet Deewam Spe-\nku/ wiſna Augſtiba irr pahr-\nsraëln/ un wiſna Spehks pal-\ntahm augſtahm Padebbetim.\n"
    },
    {
      "n": 36,
      "column": "right",
      "text": "Deews tu effi bihjajatt\nis tawas twehtas Weetas / t-\nSTIPRAJS Ifraë-\nDEEWS/ wiſch dohs teer-\nLandim Stiprumu un Spehku-\nflawehts irr Deews.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
